}

def validate_csrf_protection(headers: Dict[str, Any]) -> bool:
    if not isinstance(headers, dict):
        return False

    lowered = {}
    for k, v in headers.items():
        if isinstance(k, str):
            lowered[k.lower()] = v

    header_candidates = [
        "x-csrf-token",
